powerpagecomponent.content:
{
  "copy": "{% assign homeurl = website.adx_partialurl %}
<section class="esi-hero">
  <div class="esi-hero-inner">
    <div class="esi-hero-copy">
      <h1>Upload supporting files</h1>
      <p>Add screenshots, forms, or other documents that help explain your submitted service request.</p>
    </div>
    {% if user %}
    <div class="esi-user-card" aria-label="Signed in customer">
      <span class="esi-user-label">Signed in</span>
      <strong>{{ user.fullname | default: user.emailaddress1 | escape }}</strong>
      <span>Customer account</span>
    </div>
    {% endif %}
  </div>
</section>

{% if user and request.params.id %}
<main class="esi-shell esi-document-shell" id="mainContent" data-esi-document-page data-request-id="{{ request.params.id | escape }}">
  <div class="esi-workspace-banner">
    <div>
      <strong>Secure file upload</strong>
      <span>Files added here are stored securely with this service request.</span>
    </div>
    <a class="esi-secondary esi-link-button" href="/">Return to intake</a>
  </div>
  <div class="esi-document-status" data-document-status role="status" aria-live="polite">
    Loading the file upload area for this request...
  </div>
  <section class="esi-form esi-document-upload">
    {% entityform name: 'ESI - Service Request SharePoint Documents' %}
  </section>
</main>
{% elsif user %}
<main class="esi-shell esi-auth-shell" id="mainContent">
  <section class="esi-auth-gate">
    <div>
      <span class="esi-preview-label">Missing request</span>
      <h2>Open this page from a submitted request</h2>
      <p>The upload page needs a service request ID so files can be saved to the correct request.</p>
      <a class="esi-primary esi-link-button" href="/">Return to intake</a>
    </div>
  </section>
</main>
{% else %}
<main class="esi-shell esi-auth-shell" id="mainContent">
  <section class="esi-auth-gate">
    <div>
      <span class="esi-preview-label">Secure upload</span>
      <h2>Sign in to upload files</h2>
      <p>Please sign in so we can confirm you have access to this service request and its documents.</p>
      <a class="esi-primary esi-link-button" href="{% if homeurl %}/{{ homeurl }}{% endif %}{{ website.sign_in_url_substitution }}">Sign in to continue</a>
    </div>
  </section>
</main>
{% endif %}
",
  "customcss": ":root {
  --esi-blue: #006fb6;
  --esi-blue-dark: #005a96;
  --esi-blue-soft: #e6f2fa;
  --esi-ink: #17202b;
  --esi-muted: #5d6b7b;
  --esi-line: #d9e1ea;
  --esi-line-strong: #b8c4d2;
  --esi-page: #f6f8fb;
  --esi-surface: #ffffff;
  --esi-surface-soft: #f8fafc;
  --esi-hint: #b8c2cc;
  --esi-green: #0f7b45;
  --esi-green-soft: #e7f6ee;
  --esi-amber: #9a5b00;
  --esi-amber-soft: #fff4e0;
  --esi-red: #b42318;
  --esi-red-soft: #fdecec;
  --esi-radius: 8px;
  --esi-shadow: 0 18px 50px rgba(23, 32, 43, 0.08);
}

body {
  background: var(--esi-page);
  color: var(--esi-ink);
}

.static-top.navbar-dark {
  background: var(--esi-surface) !important;
  border-bottom: 1px solid var(--esi-line);
  box-shadow: 0 2px 14px rgba(23, 32, 43, 0.06);
}

.static-top.navbar-dark .container.custom-container {
  max-width: 1180px;
}

.navbar-dark .navbar-nav > li > a,
.navbar-dark .navbar-nav > li.dropdown > a,
.static-top.navbar-dark .navbar-brand a span {
  color: var(--esi-ink) !important;
}

.navbar-dark .navbar-nav > li > a:hover,
.navbar-dark .navbar-nav > li.dropdown > a:hover,
.navbar-dark .navbar-nav > li > a:focus {
  color: var(--esi-blue) !important;
}

.esi-site-brand {
  align-items: center;
  color: var(--esi-ink);
  display: inline-flex;
  gap: 0;
  text-decoration: none;
}

.esi-site-logo {
  display: block;
  flex: 0 0 auto;
  height: auto;
  max-height: 50px;
  object-fit: contain;
  width: min(240px, 50vw);
}

.esi-site-title {
  font-size: 22px;
  font-weight: 800;
  letter-spacing: 0;
}

.esi-hero {
  background: linear-gradient(180deg, #eef7fc 0%, var(--esi-page) 88%);
  border-bottom: 1px solid rgba(217, 225, 234, 0.8);
  padding: 48px 24px 36px;
}

.esi-hero-inner,
.esi-shell {
  margin: 0 auto;
  max-width: 1180px;
}

.esi-hero-inner {
  align-items: flex-start;
  display: flex;
  gap: 32px;
  justify-content: space-between;
}

.esi-hero-copy {
  max-width: 820px;
}

.esi-hero h1 {
  color: var(--esi-blue-dark);
  font-family: "Segoe UI", Arial, sans-serif;
  font-size: 40px;
  font-weight: 700;
  letter-spacing: 0;
  line-height: 1.14;
  margin: 0 0 14px;
  text-wrap: balance;
}

.esi-hero p {
  color: var(--esi-muted);
  font-size: 18px;
  line-height: 1.55;
  margin: 0;
}

.esi-user-card {
  background: rgba(255, 255, 255, 0.88);
  border: 1px solid var(--esi-line);
  border-radius: var(--esi-radius);
  box-shadow: 0 12px 34px rgba(23, 32, 43, 0.06);
  color: var(--esi-muted);
  display: grid;
  gap: 4px;
  min-width: 260px;
  padding: 18px;
}

.esi-user-card strong {
  color: var(--esi-ink);
  font-size: 16px;
}

.esi-user-label,
.esi-section-kicker,
.esi-preview-label {
  color: var(--esi-blue);
  font-size: 12px;
  font-weight: 800;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.esi-shell {
  padding: 28px 24px 56px;
}

.esi-workspace-banner,
.esi-form,
.esi-preview,
.esi-auth-gate {
  background: var(--esi-surface);
  border: 1px solid var(--esi-line);
  border-radius: var(--esi-radius);
}

.esi-workspace-banner {
  align-items: center;
  display: flex;
  gap: 16px;
  justify-content: space-between;
  margin-bottom: 20px;
  padding: 16px 18px;
}

.esi-workspace-banner div {
  display: grid;
  gap: 3px;
}

.esi-workspace-banner span:not(.esi-status-pill) {
  color: var(--esi-muted);
}

.esi-document-status {
  background: var(--esi-blue-soft);
  border: 1px solid rgba(0, 111, 182, 0.18);
  border-radius: var(--esi-radius);
  color: var(--esi-blue-dark);
  font-size: 14px;
  font-weight: 700;
  line-height: 1.45;
  margin-bottom: 16px;
  padding: 14px 16px;
}

.esi-document-status.is-ready {
  background: var(--esi-green-soft);
  border-color: rgba(15, 123, 69, 0.22);
  color: var(--esi-green);
}

.esi-document-status.is-warning {
  background: var(--esi-amber-soft);
  border-color: rgba(154, 91, 0, 0.25);
  color: var(--esi-amber);
}

.esi-document-status.is-error {
  background: var(--esi-red-soft);
  border-color: rgba(180, 35, 24, 0.22);
  color: var(--esi-red);
}

.esi-hidden-new-folder {
  display: none !important;
}

.esi-status-pill,
.esi-preview-state,
.esi-badge {
  border-radius: 999px;
  display: inline-flex;
  font-size: 12px;
  font-weight: 800;
  line-height: 1;
  padding: 8px 10px;
  white-space: nowrap;
}

.esi-status-pill,
.esi-preview-state.is-ready,
.esi-badge.is-green {
  background: var(--esi-green-soft);
  color: var(--esi-green);
}

.esi-preview-state,
.esi-badge {
  background: var(--esi-blue-soft);
  color: var(--esi-blue);
}

.esi-preview-state.is-warning,
.esi-badge.is-amber {
  background: var(--esi-amber-soft);
  color: var(--esi-amber);
}

.esi-preview-state.is-error,
.esi-badge.is-red {
  background: var(--esi-red-soft);
  color: var(--esi-red);
}

.esi-steps {
  display: grid;
  gap: 12px;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  margin-bottom: 24px;
}

.esi-steps button {
  align-items: center;
  background: var(--esi-surface);
  border: 1px solid var(--esi-line);
  border-radius: var(--esi-radius);
  color: var(--esi-muted);
  cursor: pointer;
  display: flex;
  gap: 12px;
  min-height: 76px;
  padding: 14px;
  text-align: left;
}

.esi-steps button:hover {
  border-color: var(--esi-line-strong);
  box-shadow: 0 8px 22px rgba(23, 32, 43, 0.06);
}

.esi-steps button.is-active {
  border-color: var(--esi-blue);
  box-shadow: 0 0 0 3px rgba(0, 111, 182, 0.12);
  color: var(--esi-ink);
}

.esi-steps button.is-complete {
  border-color: rgba(15, 123, 69, 0.35);
}

.esi-step-index {
  align-items: center;
  background: var(--esi-surface-soft);
  border: 1px solid var(--esi-line);
  border-radius: 999px;
  color: var(--esi-muted);
  display: inline-flex;
  flex: 0 0 auto;
  font-weight: 800;
  height: 34px;
  justify-content: center;
  width: 34px;
}

.esi-steps button.is-active .esi-step-index {
  background: var(--esi-blue);
  border-color: var(--esi-blue);
  color: #ffffff;
}

.esi-steps button.is-complete .esi-step-index {
  background: var(--esi-green);
  border-color: var(--esi-green);
  color: #ffffff;
  font-size: 18px;
  line-height: 1;
}

.esi-steps strong,
.esi-steps small {
  display: block;
}

.esi-steps strong {
  color: var(--esi-ink);
  font-size: 14px;
  margin-bottom: 3px;
}

.esi-steps small {
  color: var(--esi-muted);
  font-size: 12px;
}

.esi-layout {
  align-items: start;
  display: grid;
  gap: 24px;
  grid-template-columns: minmax(0, 1fr) 360px;
}

.esi-form {
  box-shadow: var(--esi-shadow);
  overflow: hidden;
}

.esi-step {
  display: none;
  padding: 28px;
}

.esi-step.is-active {
  display: block;
}

.esi-section-heading {
  border-bottom: 1px solid var(--esi-line);
  margin: -2px 0 24px;
  padding-bottom: 20px;
}

.esi-section-heading h2,
.esi-preview h2,
.esi-auth-gate h2 {
  color: var(--esi-ink);
  font-size: 24px;
  font-weight: 800;
  letter-spacing: 0;
  line-height: 1.2;
  margin: 7px 0 8px;
}

.esi-section-heading p,
.esi-preview p,
.esi-auth-gate p,
.esi-muted {
  color: var(--esi-muted);
  line-height: 1.55;
  margin: 0;
}

.esi-two-column {
  display: grid;
  gap: 18px;
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.esi-form label {
  color: var(--esi-ink);
  display: grid;
  font-weight: 700;
  gap: 8px;
  margin-bottom: 18px;
}

.esi-form label > span {
  align-items: baseline;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.esi-form label em {
  color: var(--esi-muted);
  font-size: 12px;
  font-style: normal;
  font-weight: 700;
}

.esi-form input,
.esi-form select,
.esi-form textarea {
  background: #ffffff;
  border: 1px solid var(--esi-line);
  border-radius: 6px;
  color: var(--esi-ink);
  font: inherit;
  font-weight: 500;
  min-height: 46px;
  padding: 11px 12px;
  width: 100%;
}

.esi-form textarea {
  line-height: 1.5;
  min-height: 132px;
  resize: vertical;
}

.esi-form input::placeholder,
.esi-form textarea::placeholder {
  color: var(--esi-hint) !important;
  font-style: italic;
  font-weight: 400;
  opacity: 1;
}

.esi-form input:focus,
.esi-form select:focus,
.esi-form textarea:focus {
  border-color: var(--esi-blue);
  box-shadow: 0 0 0 3px rgba(0, 111, 182, 0.14);
  outline: none;
}

.esi-form input.is-invalid,
.esi-form select.is-invalid,
.esi-form textarea.is-invalid {
  border-color: var(--esi-red);
  box-shadow: 0 0 0 3px rgba(180, 35, 24, 0.1);
}

.esi-upload {
  background: var(--esi-surface-soft);
  border: 1px dashed var(--esi-line-strong);
  border-radius: var(--esi-radius);
  padding: 22px;
}

.esi-upload-title {
  color: var(--esi-ink);
  font-size: 16px;
  font-weight: 800;
}

.esi-upload-help {
  color: var(--esi-muted);
  font-size: 14px;
  font-weight: 500 !important;
}

.esi-upload-info {
  display: grid;
  gap: 10px;
}

.esi-upload-info ul {
  color: var(--esi-muted);
  display: grid;
  gap: 7px;
  line-height: 1.45;
  margin: 2px 0 0;
  padding-left: 20px;
}

.esi-file-list {
  display: grid;
  gap: 8px;
  margin-top: -4px;
}

.esi-file-list div {
  align-items: center;
  background: #ffffff;
  border: 1px solid var(--esi-line);
  border-radius: 6px;
  color: var(--esi-muted);
  display: flex;
  gap: 10px;
  justify-content: space-between;
  padding: 10px 12px;
}

.esi-file-list strong {
  color: var(--esi-ink);
}

.esi-check {
  align-items: center;
  background: var(--esi-surface-soft);
  border: 1px solid var(--esi-line);
  border-radius: var(--esi-radius);
  display: flex !important;
  gap: 10px;
  padding: 14px;
}

.esi-check input {
  min-height: auto;
  width: auto;
}

.esi-review {
  display: grid;
  gap: 12px;
  margin-bottom: 18px;
}

.esi-review-row {
  background: var(--esi-surface-soft);
  border: 1px solid var(--esi-line);
  border-radius: 6px;
  display: grid;
  gap: 4px;
  padding: 13px 14px;
}

.esi-review-row span {
  color: var(--esi-muted);
  font-size: 12px;
  font-weight: 800;
  text-transform: uppercase;
}

.esi-review-row strong {
  color: var(--esi-ink);
  font-size: 15px;
}

.esi-action-bar {
  align-items: center;
  background: rgba(255, 255, 255, 0.96);
  border-top: 1px solid var(--esi-line);
  bottom: 0;
  display: flex;
  gap: 12px;
  justify-content: flex-end;
  margin: 28px -28px -28px;
  padding: 16px 28px;
  position: sticky;
  z-index: 2;
}

.esi-action-bar > span {
  color: var(--esi-muted);
  font-size: 14px;
  margin-right: auto;
}

.esi-primary,
.esi-secondary {
  align-items: center;
  border-radius: 6px;
  cursor: pointer;
  display: inline-flex;
  font-weight: 800;
  justify-content: center;
  min-height: 44px;
  padding: 11px 16px;
  text-decoration: none;
}

.esi-primary {
  background: var(--esi-blue);
  border: 1px solid var(--esi-blue);
  color: #ffffff;
}

.esi-primary:hover,
.esi-primary:focus {
  background: var(--esi-blue-dark);
  border-color: var(--esi-blue-dark);
  color: #ffffff;
  text-decoration: none;
}

.esi-secondary {
  background: #ffffff;
  border: 1px solid var(--esi-line-strong);
  color: var(--esi-ink);
}

.esi-secondary:hover,
.esi-secondary:focus {
  background: var(--esi-surface-soft);
  color: var(--esi-ink);
  text-decoration: none;
}

.esi-primary:focus-visible,
.esi-secondary:focus-visible,
.esi-steps button:focus-visible {
  outline: 3px solid rgba(0, 111, 182, 0.24);
  outline-offset: 2px;
}

.esi-primary:disabled {
  cursor: wait;
  opacity: 0.65;
}

.esi-step-error {
  background: var(--esi-red-soft);
  border: 1px solid rgba(180, 35, 24, 0.2);
  border-radius: 6px;
  color: var(--esi-red);
  display: none;
  font-weight: 800;
  margin-top: 8px;
  padding: 11px 12px;
}

.esi-step-error.is-visible {
  display: block;
}

.esi-result {
  border: 0;
  clip: rect(0 0 0 0);
  height: 1px;
  margin: -1px;
  overflow: hidden;
  padding: 0;
  position: absolute;
  white-space: nowrap;
  width: 1px;
}

.esi-submit-modal {
  display: none;
}

.esi-submit-modal.is-visible {
  align-items: center;
  display: flex;
  inset: 0;
  justify-content: center;
  padding: 24px;
  position: fixed;
  z-index: 2000;
}

.esi-submit-modal-backdrop {
  background: rgba(23, 32, 43, 0.45);
  inset: 0;
  position: absolute;
}

.esi-submit-dialog {
  background: var(--esi-surface);
  border: 1px solid var(--esi-line);
  border-top: 5px solid var(--esi-blue);
  border-radius: var(--esi-radius);
  box-shadow: 0 28px 80px rgba(23, 32, 43, 0.28);
  display: grid;
  gap: 18px;
  max-width: 600px;
  outline: none;
  padding: 30px;
  position: relative;
  width: min(100%, 600px);
}

.esi-submit-modal.is-success .esi-submit-dialog {
  border-top-color: var(--esi-green);
}

.esi-submit-modal.is-error .esi-submit-dialog {
  border-top-color: var(--esi-red);
}

.esi-submit-icon {
  align-items: center;
  background: var(--esi-blue-soft);
  border-radius: 999px;
  color: var(--esi-blue);
  display: inline-flex;
  font-size: 15px;
  font-weight: 900;
  height: 48px;
  justify-content: center;
  width: 48px;
}

.esi-submit-modal.is-success .esi-submit-icon {
  background: var(--esi-green-soft);
  color: var(--esi-green);
}

.esi-submit-modal.is-error .esi-submit-icon {
  background: var(--esi-red-soft);
  color: var(--esi-red);
}

.esi-submit-modal.is-info .esi-submit-icon::before {
  animation: esi-spin 0.9s linear infinite;
  border: 3px solid rgba(0, 111, 182, 0.18);
  border-top-color: var(--esi-blue);
  border-radius: 999px;
  content: "";
  height: 24px;
  width: 24px;
}

.esi-submit-content {
  display: grid;
  gap: 10px;
}

.esi-submit-kicker {
  color: var(--esi-blue);
  font-size: 12px;
  font-weight: 900;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.esi-submit-modal.is-success .esi-submit-kicker {
  color: var(--esi-green);
}

.esi-submit-modal.is-error .esi-submit-kicker {
  color: var(--esi-red);
}

.esi-submit-content h2 {
  color: var(--esi-ink);
  font-size: 28px;
  font-weight: 800;
  line-height: 1.15;
  margin: 0;
}

.esi-submit-content p {
  color: var(--esi-muted);
  font-size: 16px;
  line-height: 1.55;
  margin: 0;
}

.esi-confirmation-number {
  background: var(--esi-blue-soft);
  border: 1px solid rgba(0, 111, 182, 0.18);
  border-radius: var(--esi-radius);
  display: grid;
  gap: 4px;
  margin-top: 4px;
  padding: 14px 16px;
}

.esi-confirmation-number span {
  color: var(--esi-blue);
  font-size: 12px;
  font-weight: 900;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.esi-confirmation-number strong {
  color: var(--esi-blue-dark);
  font-size: 22px;
  font-weight: 900;
  letter-spacing: 0.02em;
}

.esi-submit-next {
  color: var(--esi-muted);
  display: grid;
  gap: 7px;
  line-height: 1.45;
  margin: 4px 0 0;
  padding-left: 20px;
}

.esi-submit-actions {
  border-top: 1px solid var(--esi-line);
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  justify-content: flex-end;
  padding-top: 18px;
}

@keyframes esi-spin {
  to {
    transform: rotate(360deg);
  }
}

.esi-preview {
  box-shadow: 0 12px 30px rgba(23, 32, 43, 0.06);
  padding: 22px;
  position: sticky;
  top: 18px;
}

.esi-preview-header {
  align-items: center;
  display: flex;
  gap: 10px;
  justify-content: space-between;
  margin-bottom: 12px;
}

.esi-preview h2 {
  font-size: 22px;
  margin-bottom: 18px;
}

.esi-preview-grid {
  display: grid;
  gap: 10px;
  margin: 18px 0;
}

.esi-preview-grid div {
  background: var(--esi-surface-soft);
  border: 1px solid var(--esi-line);
  border-radius: 6px;
  display: grid;
  gap: 5px;
  padding: 12px;
}

.esi-preview-grid span {
  color: var(--esi-muted);
  font-size: 12px;
  font-weight: 800;
  text-transform: uppercase;
}

.esi-preview-grid strong {
  color: var(--esi-ink);
  font-size: 15px;
}

.esi-preview-grid .esi-badge {
  color: var(--esi-blue);
  font-size: 12px;
  width: max-content;
}

.esi-preview-grid .esi-badge.is-green {
  color: var(--esi-green);
}

.esi-preview-grid .esi-badge.is-amber {
  color: var(--esi-amber);
}

.esi-preview-grid .esi-badge.is-red {
  color: var(--esi-red);
}

.esi-preview-note {
  background: var(--esi-blue-soft);
  border-radius: 6px;
  color: var(--esi-muted);
  margin-top: 16px;
  padding: 12px;
}

.esi-auth-shell {
  padding-top: 40px;
}

.esi-auth-gate {
  align-items: stretch;
  box-shadow: var(--esi-shadow);
  display: grid;
  gap: 24px;
  grid-template-columns: minmax(0, 1fr) 340px;
  padding: 34px;
}

.esi-auth-gate h2 {
  font-size: 30px;
}

.esi-auth-gate .esi-link-button {
  margin-top: 22px;
}

.esi-auth-panel {
  background: var(--esi-surface-soft);
  border: 1px solid var(--esi-line);
  border-radius: var(--esi-radius);
  padding: 22px;
}

.esi-auth-panel strong {
  display: block;
  margin-bottom: 12px;
}

.esi-auth-panel ul {
  color: var(--esi-muted);
  display: grid;
  gap: 10px;
  margin: 0;
  padding-left: 18px;
}

@media (max-width: 980px) {
  .esi-hero-inner,
  .esi-workspace-banner {
    display: grid;
  }

  .esi-user-card {
    min-width: 0;
  }

  .esi-steps {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .esi-layout,
  .esi-auth-gate {
    grid-template-columns: 1fr;
  }

  .esi-preview {
    position: static;
  }
}

@media (max-width: 640px) {
  .esi-hero {
    padding: 34px 18px 28px;
  }

  .esi-hero h1 {
    font-size: 31px;
  }

  .esi-shell {
    padding: 20px 16px 40px;
  }

  .esi-steps {
    display: grid;
    gap: 8px;
    grid-template-columns: 1fr;
  }

  .esi-steps button {
    min-height: 64px;
  }

  .esi-two-column {
    grid-template-columns: 1fr;
  }

  .esi-step {
    padding: 22px;
  }

  .esi-action-bar {
    align-items: stretch;
    flex-direction: column;
    margin: 24px -22px -22px;
    padding: 14px 22px;
    position: static;
  }

  .esi-action-bar > span {
    margin-right: 0;
  }

  .esi-primary,
  .esi-secondary {
    width: 100%;
  }

  .esi-submit-modal.is-visible {
    align-items: flex-end;
    padding: 16px;
  }

  .esi-submit-dialog {
    padding: 24px;
  }

  .esi-submit-content h2 {
    font-size: 24px;
  }

  .esi-submit-actions {
    align-items: stretch;
    flex-direction: column;
  }

  .esi-preview-header,
  .esi-workspace-banner {
    align-items: stretch;
  }

  .esi-site-logo {
    max-height: 38px;
    width: min(190px, 58vw);
  }
}
",
  "customjavascript": "(function () {
  const root = document.querySelector("[data-esi-document-page]");
  if (!root) return;

  const status = root.querySelector("[data-document-status]");
  const uploadArea = root.querySelector(".esi-document-upload");
  if (!status || !uploadArea) return;

  function setStatus(tone, message) {
    status.className = `esi-document-status ${tone ? `is-${tone}` : ""}`.trim();
    status.textContent = message;
  }

  function textOf(element) {
    return (element.getAttribute("aria-label") || element.getAttribute("title") || element.textContent || "")
      .replace(/\s+/g, " ")
      .trim();
  }

  function replaceExactText(from, to) {
    const walker = document.createTreeWalker(uploadArea, NodeFilter.SHOW_TEXT);
    const matches = [];
    while (walker.nextNode()) {
      if (walker.currentNode.nodeValue.trim() === from) {
        matches.push(walker.currentNode);
      }
    }
    matches.forEach((node) => {
      node.nodeValue = node.nodeValue.replace(from, to);
    });
  }

  function applyPortalLanguage() {
    [
      ["Request Summary", "Request details"],
      ["Confirmation Number", "Confirmation number"],
      ["Request Title", "Request title"],
      ["Lifecycle Status", "Status"],
      ["Customer Visible Updates", "Updates from Mitacs"],
      ["SharePoint Documents", "Supporting files"],
      ["Supporting Documents", "Uploaded files"],
      ["There are no folders or files to display.", "No files have been uploaded yet."]
    ].forEach(([from, to]) => replaceExactText(from, to));
  }

  function hideNewFolderActions() {
    uploadArea.querySelectorAll("button, a, input, span, li").forEach((element) => {
      if (!/^new folder$/i.test(textOf(element))) return;
      const action = element.closest("button, a, li, .dropdown-item, .toolbar-item") || element;
      action.hidden = true;
      action.setAttribute("aria-hidden", "true");
      action.classList.add("esi-hidden-new-folder");
    });
  }

  function applyUploadUx() {
    applyPortalLanguage();
    hideNewFolderActions();
  }

  function hasSharePointDocumentControl() {
    return Boolean(uploadArea.querySelector([
      "#SharePointDocuments",
      "[data-name='SharePointDocuments']",
      "[id*='SharePointDocuments']",
      "[id*='sharepoint']",
      "[class*='sharepoint']",
      ".entity-grid",
      ".subgrid"
    ].join(",")));
  }

  function hasPermissionOrRenderingError() {
    const text = uploadArea.textContent || "";
    return /permission|access denied|not authorized|could not find|record not found|error/i.test(text);
  }

  function evaluateUploadArea() {
    applyUploadUx();

    if (hasSharePointDocumentControl()) {
      setStatus("ready", "File upload is ready. Use the file list below to add supporting files for this request.");
      return true;
    }

    if (hasPermissionOrRenderingError()) {
      setStatus("error", "The file upload area could not load for this request. Confirm this request belongs to your signed-in account and try again.");
      return true;
    }

    return false;
  }

  if (evaluateUploadArea()) return;

  const observer = new MutationObserver(() => {
    if (evaluateUploadArea()) observer.disconnect();
  });
  observer.observe(uploadArea, { childList: true, subtree: true });

  window.setTimeout(() => {
    if (!evaluateUploadArea()) {
      setStatus("warning", "The file upload area is still loading. If the file list does not appear, refresh this page.");
    }
    observer.disconnect();
  }, 8000);
})();
